import{_ as e,o as d,c as o,a0 as r}from"./chunks/framework.7S7UUFQz.js";const m=JSON.parse('{"title":"H3 And TerritoryKit Comparison","description":"","frontmatter":{},"headers":[],"relativePath":"h3-comparison.md","filePath":"h3-comparison.md"}'),a={name:"h3-comparison.md"};function i(n,t,l,s,c,p){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="h3-and-territorykit-comparison" tabindex="-1">H3 And TerritoryKit Comparison <a class="header-anchor" href="#h3-and-territorykit-comparison" aria-label="Permalink to &quot;H3 And TerritoryKit Comparison&quot;">​</a></h1><p>TerritoryKit is inspired by the developer experience of H3, not by H3&#39;s geometry model. H3 uses globally indexed regular hexagon and pentagon cells. TerritoryKit uses dataset-defined Polygon and MultiPolygon territories.</p><table tabindex="0"><thead><tr><th>Criterion</th><th>H3</th><th>TerritoryKit</th></tr></thead><tbody><tr><td>Geometry</td><td>Regular hexagon/pentagon cells</td><td>Irregular Polygon/MultiPolygon zones</td></tr><tr><td>Coverage</td><td>Global mathematical grid</td><td>Dataset-dependent, optionally global</td></tr><tr><td>Hierarchy</td><td>Built-in resolution system</td><td>Dataset-defined level and parent-child system</td></tr><tr><td>Neighbor lookup</td><td>Mathematical grid traversal</td><td>Graph-based adjacency and logical connections</td></tr><tr><td>Rendering</td><td>Not included</td><td>Adapter packages such as MapLibre</td></tr><tr><td>Game features</td><td>Not included</td><td>Kept outside core, later <code>game</code> package</td></tr><tr><td>Administrative boundaries</td><td>Approximation through cells</td><td>Native fit for province/district/neighborhood boundaries</td></tr><tr><td>Performance</td><td>Very high by design</td><td>Depends on spatial index, geometry complexity, and dataset quality</td></tr></tbody></table><h2 id="api-mapping" tabindex="-1">API Mapping <a class="header-anchor" href="#api-mapping" aria-label="Permalink to &quot;API Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>H3 API</th><th>TerritoryKit API</th><th>Status</th></tr></thead><tbody><tr><td><code>latLngToCell</code></td><td><code>latLngToZone</code></td><td>Baseline implemented</td></tr><tr><td><code>cellToBoundary</code></td><td><code>zoneToBoundary</code></td><td>Baseline implemented</td></tr><tr><td><code>gridDisk</code></td><td><code>zoneNeighbors</code></td><td>Baseline implemented</td></tr><tr><td><code>cellToParent</code></td><td><code>zoneToParent</code></td><td>Baseline implemented</td></tr><tr><td><code>cellToChildren</code></td><td><code>zoneToChildren</code></td><td>Baseline implemented</td></tr><tr><td><code>polygonToCells</code></td><td><code>polygonToZones</code></td><td>Implemented</td></tr><tr><td><code>isValidCell</code></td><td><code>isValidZone</code></td><td>Baseline implemented</td></tr></tbody></table><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>TerritoryKit will not recreate H3&#39;s global geodesic grid.</li><li>TerritoryKit will not treat game state as core geometry.</li><li>TerritoryKit will not hide dataset quality problems behind silent repairs.</li></ul><h2 id="product-positioning" tabindex="-1">Product Positioning <a class="header-anchor" href="#product-positioning" aria-label="Permalink to &quot;Product Positioning&quot;">​</a></h2><p>TerritoryKit succeeds when it can manage real or custom polygon regions through a predictable, versioned, H3-like API across Node.js, browser maps, and backend services.</p>',9)])])}const g=e(a,[["render",i]]);export{m as __pageData,g as default};
